BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?elem ?type ?name WHERE {
  ?elem rdf:type ?type .
  OPTIONAL { ?elem vocab:NamedElement_name ?name . }
  FILTER(
    (BOUND(?name) && CONTAINS(LCASE(STR(?name)), LCASE("flowdown")))
    || (BOUND(?name) && CONTAINS(LCASE(STR(?name)), LCASE("aps requirements")))
  )
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?flow ?source ?sourceName ?target ?targetName WHERE {
  ?flow rdf:type vocab:InformationFlow .
  ?flow vocab:InformationFlow_informationSource ?source .
  ?flow vocab:InformationFlow_informationTarget ?target .

  OPTIONAL { ?source vocab:NamedElement_name ?sourceName . }
  OPTIONAL { ?target vocab:NamedElement_name ?targetName . }

  VALUES ?reqDoc {
    <http://api.koneksys.com/cameo/TMT/block/TMT::Project::Work%2520Packages::Telescope::WorkPackages::Control::Alignment%2520and%2520Phasing%2520System::Systems%2520Engineering::03%2520Processes::Information%2520Flow::Requirements%2520Information%2520Flow::L2%2520APS%2520Requirements%2520Document>
  }

  FILTER( (?source = ?reqDoc && CONTAINS(LCASE(STR(?targetName)), LCASE("APS Requirements Flowdown")))
       || (?target = ?reqDoc && CONTAINS(LCASE(STR(?sourceName)), LCASE("APS Requirements Flowdown"))) )
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?flow ?role ?other ?otherName WHERE {
  {
    ?flow rdf:type vocab:InformationFlow ;
          vocab:InformationFlow_informationSource <http://api.koneksys.com/cameo/TMT/block/TMT::Project::Work%2520Packages::Telescope::WorkPackages::Control::Alignment%2520and%2520Phasing%2520System::Systems%2520Engineering::03%2520Processes::Information%2520Flow::Requirements%2520Information%2520Flow::L2%2520APS%2520Requirements%2520Document> ;
          vocab:InformationFlow_informationTarget ?other .
    BIND("source->target" AS ?role)
  }
  UNION
  {
    ?flow rdf:type vocab:InformationFlow ;
          vocab:InformationFlow_informationTarget <http://api.koneksys.com/cameo/TMT/block/TMT::Project::Work%2520Packages::Telescope::WorkPackages::Control::Alignment%2520and%2520Phasing%2520System::Systems%2520Engineering::03%2520Processes::Information%2520Flow::Requirements%2520Information%2520Flow::L2%2520APS%2520Requirements%2520Document> ;
          vocab:InformationFlow_informationSource ?other .
    BIND("target<-source" AS ?role)
  }
  OPTIONAL { ?other vocab:NamedElement_name ?otherName . }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?flow ?endpoint ?other ?otherName WHERE {
  VALUES ?doc {
    <http://api.koneksys.com/cameo/TMT/block/TMT::Project::Work%2520Packages::Telescope::WorkPackages::Control::Alignment%2520and%2520Phasing%2520System::Systems%2520Engineering::03%2520Processes::Information%2520Flow::Requirements%2520Information%2520Flow::L2%2520APS%2520Requirements%2520Document>
  }
  OPTIONAL {
    ?doc vocab:_informationFlowOfInformationSource ?flow .
    OPTIONAL { ?flow vocab:InformationFlow_informationTarget ?other . }
  }
  OPTIONAL {
    ?doc vocab:_informationFlowOfInformationTarget ?flow .
    OPTIONAL { ?flow vocab:InformationFlow_informationSource ?other . }
  }
  OPTIONAL { ?other vocab:NamedElement_name ?otherName . }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?flow ?other ?otherName WHERE {
  VALUES ?doc {
    <http://api.koneksys.com/cameo/TMT/block/TMT::Project::Work%2520Packages::Telescope::WorkPackages::Control::Alignment%2520and%2520Phasing%2520System::Systems%2520Engineering::03%2520Processes::Information%2520Flow::Requirements%2520Information%2520Flow::L2%2520APS%2520Requirements%2520Document>
  }

  {
    ?doc vocab:_informationFlowOfInformationSource ?flow .
  }
  UNION
  {
    ?doc vocab:_informationFlowOfInformationTarget ?flow .
  }

  OPTIONAL { ?flow vocab:InformationFlow_informationSource ?other . }
  OPTIONAL { ?flow vocab:InformationFlow_informationTarget ?other . }

  OPTIONAL { ?other vocab:NamedElement_name ?otherName . }

  FILTER(BOUND(?otherName) && CONTAINS(LCASE(STR(?otherName)), LCASE("APS Requirements Flowdown")))
}
LIMIT 25
